<?php

namespace Worldpay\Api\Builders\PaymentQuery;

use Worldpay\Api\ApiResponse;
use Worldpay\Api\Exceptions\ApiClientException;
use Worldpay\Api\Providers\AccessWorldpayConfigProvider;
use Worldpay\Api\Services\AccessWorldpay\PaymentQueriesApiService;
use Worldpay\Api\Services\PaymentQueryServiceInterface;

class PaymentQueryBuilder
{
	/**
	 * @var string
	 */
	public string $linkData;

	/**
	 * @var string Unique paymentId generated for each payment.
	 */
	public string $paymentId;

	/**
	 * @var string An ISO 8601 date-time supplied as a string. Filters for payments that occurred after the specified date-time. Must be supplied alongside endDate.
	 */
	public string $startDate;

	/**
	 * @var string An ISO 8601 date-time supplied as a string. Filters for payments that occurred below the specified date-time. Must be supplied alongside startDate.
	 */
	public string $endDate;

	/**
	 * @var string The maximum number of payments to be returned in the response (max 300).
	 */
	public string $pageSize;

	/**
	 * @var string $receivedEvents A specific event name or can be grouped together as comma separated values.
	 */
	public string $receivedEvents;

	/**
	 * @var string A unique reference generated by you, used to identify a payment throughout its lifecycle.
	 */
	public string $transactionReference;

	/**
	 * @return ApiResponse
	 * @throws ApiClientException
	 * @throws \Exception
	 */
	public function execute(): ApiResponse {
		$configProvider = AccessWorldpayConfigProvider::instance();
		$apiService = $configProvider->getApiService();
		if (! class_exists($apiService) || ! ((new $apiService()) instanceof PaymentQueryServiceInterface)) {
			throw new ApiClientException($configProvider->getApi() . ' does not support payment queries.');
		}
		return isset($this->paymentId) ?
			PaymentQueriesApiService::queryPaymentByPaymentId($this) :
			$apiService::queryPayment($this);
	}

	/**
	 * @return array
	 */
	public function getQueryStringParams(): array {
		return array_filter([
			'startDate' => $this->startDate ?? '',
			'endDate' => $this->endDate ?? '',
			'pageSize' => $this->pageSize ?? '',
			'transactionReference' => $this->transactionReference ?? '',
			'receivedEvents' => $this->receivedEvents ?? '',
		]);
	}

	/**
	 * @param  string  $transactionReference
	 * @return $this
	 */
	public function withTransactionReference(string $transactionReference): PaymentQueryBuilder {
		$this->transactionReference = $transactionReference;

		return $this;
	}

	/**
	 * @param  string  $paymentId
	 * @return $this
	 */
	public function withPaymentId(string $paymentId): PaymentQueryBuilder {
		$this->paymentId = $paymentId;

		return $this;
	}

	/**
	 * @param  string  $linkData
	 * @return $this
	 */
	public function withLinkData(string $linkData): PaymentQueryBuilder {
		$this->linkData = $linkData;

		return $this;
	}

	/**
	 * @param  string  $startDate
	 * @return $this
	 */
	public function withStartDate(string $startDate): PaymentQueryBuilder {
		$this->startDate = $startDate;

		return $this;
	}

	/**
	 * @param  string  $endDate
	 * @return $this
	 */
	public function withEndDate(string $endDate): PaymentQueryBuilder {
		$this->endDate = $endDate;

		return $this;
	}

	/**
	 * @param  int  $pageSize
	 * @return $this
	 */
	public function withPageSize(int $pageSize): PaymentQueryBuilder {
		$this->pageSize = $pageSize;

		return $this;
	}

	/**
	 * @param  string  $receivedEvents
	 * @return $this
	 */
	public function withReceivedEvents(string $receivedEvents): PaymentQueryBuilder {
		$this->receivedEvents = $receivedEvents;

		return $this;
	}
}
